    'dollar' => 
    array (
      'title' => 'Der Dollar',
      'lead' => 'Storia e diffusione del dollaro.',
      'blocks' => 
      array (
        0 => 
        array (
          'type' => 'figure',
          'image' => 
          array (
            'file' => 'dollaroa.jpg',
